/*
开始写题时间: 2025/8/22 14:36
大致思路:
求出所有点是否能由起点到达，能否到达由终点
tarjan 缩点后作拓扑序

提交次数: 3 次
历史提交:
第 1 次(14:58): 
100pts, Subtask 1 6*MLE
第 2 次(15:11): 
100pts, Subtask 1 6*MLE
*/
#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10,M=1e6+10;

int n,m,val[N];
int head[N],rh[N],ver[M<<1],nxt[M<<1],tot;
bool st[N],et[N],ins[N];
int dfn[N],low[N],num,c[N],cnt,du[N],minval[N],maxval[N],stk[N],top;
vector<int> g[N];

void add(int u,int v,int w){
    if(w==1){
        ver[++tot]=v,nxt[tot]=head[u],head[u]=tot;
        ver[++tot]=u,nxt[tot]=rh[v],rh[v]=tot;
    }else{
        ver[++tot]=v,nxt[tot]=head[u],head[u]=tot;
        ver[++tot]=u,nxt[tot]=head[v],head[v]=tot;
        ver[++tot]=v,nxt[tot]=rh[u],rh[u]=tot;
        ver[++tot]=u,nxt[tot]=rh[v],rh[v]=tot;
    }
}

void tarjan(int x){
    dfn[x]=low[x]=++num;
    stk[++top]=x,ins[x]=1;
    for(int i=head[x];i;i=nxt[i])
        if(st[ver[i]] && et[ver[i]]){
            if(!dfn[ver[i]]){
                tarjan(ver[i]);
                low[x]=min(low[x],low[ver[i]]);
            }else if(ins[ver[i]])
                low[x]=min(low[x],dfn[ver[i]]);
        }
    if(dfn[x]==low[x]){
        int z=0;
        minval[++cnt]=102;
        do{
            z=stk[top--],c[z]=cnt,ins[z]=0;
            minval[cnt]=min(minval[cnt],val[z]);
            maxval[cnt]=max(maxval[cnt],val[z]);
        }while(z!=x);
    }
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%d",&val[i]);
    for(int i=1,u,v,w;i<=m;i++){
        scanf("%d%d%d",&u,&v,&w);
        add(u,v,w);
    }
    queue<int> q;
    q.push(1);
    while(q.size()){
        int x=q.front();
        q.pop(),st[x]=1;
        for(int i=head[x];i;i=nxt[i])
            if(!st[ver[i]])
                q.push(ver[i]);
    }
    q.push(n);
    while(q.size()){
        int x=q.front();
        q.pop(),et[x]=1;
        for(int i=rh[x];i;i=nxt[i])
            if(!et[ver[i]])
                q.push(ver[i]);
    }
    for(int i=1;i<=n;i++)
        if(st[i] && et[i] && !dfn[i])
            tarjan(i);
    for(int i=1;i<=n;i++){
        if(!st[i] || !et[i])
            continue;
        for(int j=head[i];j;j=nxt[j])
            if(c[ver[j]]!=c[i] && c[ver[j]] && st[ver[j]] && et[ver[j]])
                g[c[i]].push_back(c[ver[j]]),du[c[ver[j]]]++;
    }
    q.push(c[1]);
    int ans=0;
    while(q.size()){
        int x=q.front();
        ans=max(ans,maxval[x]-minval[x]);
        q.pop();
        for(int y:g[x]){
            minval[y]=min(minval[y],minval[x]);
            if(!--du[y])
                q.push(y);
        }
        g[x].clear();
    }
    printf("%d",ans);
    return 0;
}
